{"mappings":"AAAA;;;;AAKA;;;;;;AAMA;;;;;;;;;;;;AAwBA;;;;AAYA;;;;;AAKA;;;;AAKA;;;;AAIA;;;;AAUA","sources":["src/index.css"],"sourcesContent":["body {\r\n    /* pink */\r\n    background-color: #0d0404;\r\n}\r\n\r\ndiv {\r\n    font-size: calc(4vw + 3.5vh);\r\n    font-weight: bold;\r\n    color: rgb(255, 91, 198);\r\n}\r\n\r\n#main_div {\r\n    display: flex;\r\n    flex-direction: column;\r\n    justify-content: center;\r\n    align-items: center;\r\n\r\n    width: 100vw;\r\n    height: 100vh;\r\n    \r\n    position: absolute;\r\n    top:0;\r\n    bottom: 0;\r\n    left: 0;\r\n    right: 0;\r\n    \r\n    margin: auto;\r\n\r\n    /* debug */\r\n    /* background-color: red; */\r\n    /* border-style: solid;\r\n    border-width: 1px;\r\n    border-color: black; */\r\n}\r\n\r\n.child {\r\n    /* TODO: add fallback font-size */\r\n    /* This strange font size looks the best out of all the ones I tried;\r\n    Maybe I should change it sometime soon, but it works fine. */\r\n    text-align: center;\r\n    \r\n    /* debug */\r\n    /* border-style: solid;\r\n    border-width: 1px;\r\n    border-color: black; */\r\n}\r\n\r\na {\r\n    padding: 1.5vw;\r\n    text-decoration: none;\r\n}\r\n\r\na:link {\r\n    /* blue */\r\n    color: rgb(1, 99, 185);\r\n}\r\n\r\na:hover {\r\n    text-decoration: underline;\r\n}\r\n\r\na:active {\r\n    /* orange */\r\n    color: rgb(236, 169, 75);\r\n}\r\n\r\n/* .shadow {\r\n    text-shadow: 2px 2px 2px black;\r\n} */\r\n\r\n/* https://stackoverflow.com/questions/826782/how-to-disable-text-selection-highlighting */\r\n.noselect {\r\n    -webkit-touch-callout: none; /* iOS Safari */\r\n      -webkit-user-select: none; /* Safari */\r\n       -khtml-user-select: none; /* Konqueror HTML */\r\n         -moz-user-select: none; /* Old versions of Firefox */\r\n          -ms-user-select: none; /* Internet Explorer/Edge */\r\n              user-select: none; /* Non-prefixed version, currently\r\n                                    supported by Chrome, Edge, Opera and Firefox */\r\n}"],"names":[],"version":3,"file":"index.61d3354a.css.map","sourceRoot":"/__parcel_source_root/"}